import React, { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { coursesAPI } from "../services/api";
import ProgressBar from "../components/ProgressBar";
import Spinner from "../components/Spinner";

const CoursePlayer = () => {
  const { id } = useParams();
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeLesson, setActiveLesson] = useState(0);
  const [completedLessons, setCompletedLessons] = useState([]);
  const [progress, setProgress] = useState(0);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const { data } = await coursesAPI.getById(id);
        setCourse(data);
      } catch { console.error("Failed to load"); }
      finally { setLoading(false); }
    };
    fetch();
  }, [id]);

  const handleCompleteLesson = async () => {
    if (completedLessons.includes(activeLesson)) return;
    try {
      const { data } = await coursesAPI.updateProgress(id, activeLesson);
      setCompletedLessons(data.completedLessons);
      setProgress(data.progress);
    } catch {
      const updated = [...completedLessons, activeLesson];
      setCompletedLessons(updated);
      setProgress(Math.round((updated.length / (course?.lessons?.length || 1)) * 100));
    }
  };

  if (loading) return <Spinner message="Loading player..." />;
  if (!course) return <div className="page-error">Course not found.</div>;

  const total = course.lessons?.length || 0;
  const current = course.lessons?.[activeLesson];

  return (
    <div style={{ height: "calc(100vh - 64px)", display: "flex", flexDirection: "column", background: "#0f0f1a" }}>
      {/* Top bar */}
      <div className="d-flex align-items-center gap-3 px-4" style={{
        height: 52, background: "#1a1a2e", borderBottom: "1px solid #2a2a4a", flexShrink: 0
      }}>
        <Link to="/my-courses" className="small" style={{ color: "#9999bb", whiteSpace: "nowrap" }}>
          <i className="bi bi-arrow-left me-1"></i>My Learning
        </Link>
        <span className="fw-semibold small flex-grow-1 text-truncate" style={{ color: "#e8e8f0" }}>{course.title}</span>
        <div className="d-flex align-items-center gap-2" style={{ minWidth: 200 }}>
          <ProgressBar progress={progress} showLabel={false} />
          <span className="small" style={{ color: "#666688", whiteSpace: "nowrap" }}>{progress}%</span>
        </div>
      </div>

      {/* Layout */}
      <div style={{ display: "flex", flex: 1, overflow: "hidden" }}>
        {/* Main */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", overflowY: "auto" }}>
          {/* Video placeholder */}
          <div style={{ background: "#000", flexShrink: 0 }}>
            <div style={{
              aspectRatio: "16/9", maxHeight: 480,
              background: "linear-gradient(135deg, #0a0a1a 0%, #1a1a3a 50%, #0a0a1a 100%)",
              display: "flex", alignItems: "center", justifyContent: "center"
            }}>
              <div className="text-center">
                <div className="mb-3" style={{
                  width: 72, height: 72, borderRadius: "50%",
                  background: "rgba(108,99,255,0.3)", border: "2px solid #6c63ff",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  margin: "0 auto", cursor: "pointer"
                }}
                  onClick={handleCompleteLesson}
                >
                  <i className="bi bi-play-fill" style={{ color: "white", fontSize: "1.5rem", paddingLeft: 4 }}></i>
                </div>
                <h5 className="fw-bold mb-1" style={{ color: "#e8e8f0" }}>{current?.title}</h5>
                <p className="small mb-0" style={{ color: "#666688" }}>Lesson {activeLesson + 1} of {total} · {current?.duration}</p>
              </div>
            </div>
          </div>

          {/* Controls */}
          <div className="p-4" style={{ borderTop: "1px solid #2a2a4a" }}>
            <div className="d-flex align-items-start justify-content-between gap-3 mb-3 flex-wrap">
              <div>
                <h5 className="fw-bold mb-1" style={{ color: "#e8e8f0" }}>{current?.title}</h5>
                <p className="small mb-0" style={{ color: "#666688" }}>{course.instructor} · {current?.duration}</p>
              </div>
              <button
                className="btn btn-sm fw-bold"
                onClick={handleCompleteLesson}
                disabled={completedLessons.includes(activeLesson)}
                style={{
                  background: completedLessons.includes(activeLesson) ? "#2a2a4a" : "#43d9ad",
                  color: completedLessons.includes(activeLesson) ? "#666688" : "#0f0f1a",
                  border: "none", borderRadius: 8, padding: "8px 18px"
                }}
              >
                {completedLessons.includes(activeLesson) ? "✅ Completed" : "Mark Complete"}
              </button>
            </div>

            <div className="d-flex align-items-center gap-3">
              <button className="btn btn-sm" onClick={() => setActiveLesson(p => p - 1)} disabled={activeLesson === 0}
                style={{ border: "1px solid #2a2a4a", color: "#9999bb", borderRadius: 8 }}>
                <i className="bi bi-arrow-left me-1"></i>Previous
              </button>
              <span className="small" style={{ color: "#666688" }}>{activeLesson + 1} / {total}</span>
              <button className="btn btn-sm" onClick={() => setActiveLesson(p => p + 1)} disabled={activeLesson === total - 1}
                style={{ border: "1px solid #2a2a4a", color: "#9999bb", borderRadius: 8 }}>
                Next<i className="bi bi-arrow-right ms-1"></i>
              </button>
            </div>
          </div>
        </div>

        {/* Sidebar toggle */}
        <button
          onClick={() => setSidebarOpen(!sidebarOpen)}
          style={{
            position: "absolute", right: sidebarOpen ? 321 : 1, top: "50%", transform: "translateY(-50%)",
            width: 20, height: 48, background: "#1a1a2e", border: "1px solid #2a2a4a",
            borderRadius: "4px 0 0 4px", color: "#9999bb", cursor: "pointer", zIndex: 10,
            display: "flex", alignItems: "center", justifyContent: "center", fontSize: "0.7rem"
          }}
        >
          <i className={`bi bi-chevron-${sidebarOpen ? "right" : "left"}`}></i>
        </button>

        {/* Sidebar */}
        {sidebarOpen && (
          <div style={{ width: 320, borderLeft: "1px solid #2a2a4a", background: "#1a1a2e", display: "flex", flexDirection: "column", flexShrink: 0 }}>
            <div className="d-flex justify-content-between align-items-center p-3" style={{ borderBottom: "1px solid #2a2a4a" }}>
              <span className="small fw-bold" style={{ color: "#e8e8f0" }}>Course Content</span>
              <span className="small" style={{ color: "#666688" }}>{completedLessons.length}/{total} done</span>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: 8 }}>
              {course.lessons?.map((lesson, idx) => (
                <div key={idx}
                  onClick={() => setActiveLesson(idx)}
                  className="d-flex align-items-center gap-2 p-2 rounded-3 mb-1"
                  style={{
                    cursor: "pointer",
                    background: activeLesson === idx ? "rgba(108,99,255,0.12)" : "transparent",
                    border: activeLesson === idx ? "1px solid #6c63ff" : "1px solid transparent",
                    transition: "all 0.15s"
                  }}
                >
                  <div className="d-flex align-items-center justify-content-center rounded-circle fw-bold"
                    style={{
                      width: 26, height: 26, flexShrink: 0, fontSize: "0.75rem",
                      background: completedLessons.includes(idx) ? "#43d9ad" : "#2a2a4a",
                      color: completedLessons.includes(idx) ? "#0f0f1a" : "#9999bb"
                    }}>
                    {completedLessons.includes(idx) ? <i className="bi bi-check"></i> : idx + 1}
                  </div>
                  <div className="flex-grow-1" style={{ minWidth: 0 }}>
                    <div className="small fw-semibold text-truncate" style={{ color: activeLesson === idx ? "#6c63ff" : "#e8e8f0" }}>
                      {lesson.title}
                    </div>
                    <div style={{ fontSize: "0.72rem", color: "#666688" }}>{lesson.duration}</div>
                  </div>
                  {activeLesson === idx && <i className="bi bi-play-fill small" style={{ color: "#6c63ff", flexShrink: 0 }}></i>}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CoursePlayer;
